import React from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  BarChart,
  Bar,
  Cell,
  PieChart,
  Pie,
  LineChart,
  Line,
  ScatterChart,
  Scatter,
  ZAxis
} from 'recharts';
import { MetricPoint, CompetitorData } from '../types';

interface TrendChartProps {
  data: MetricPoint[];
  dataKey: string;
  color: string;
  showForecast?: boolean;
}

export const TrendChart: React.FC<TrendChartProps> = ({ data, dataKey, color, showForecast }) => {
  return (
    <ResponsiveContainer width="100%" height="100%">
      <AreaChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 5 }}>
        <defs>
          <linearGradient id={`color${dataKey}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%" stopColor={color} stopOpacity={0.8}/>
            <stop offset="95%" stopColor={color} stopOpacity={0}/>
          </linearGradient>
        </defs>
        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fontSize: 10}} />
        <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10}} />
        <CartesianGrid vertical={false} strokeDasharray="3 3" stroke="#f0f0f0" />
        <Tooltip 
          contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
        />
        <Area 
          type="monotone" 
          dataKey="value" 
          stroke={color} 
          fillOpacity={1} 
          fill={`url(#color${dataKey})`} 
          name="数值"
        />
        {showForecast && (
             <Area 
             type="monotone" 
             dataKey="forecast" 
             stroke={color} 
             strokeDasharray="5 5"
             fill="none"
             name="预测值"
           />
        )}
      </AreaChart>
    </ResponsiveContainer>
  );
};

interface MultiLineChartProps {
  data: any[];
  lines: { key: string; color: string; name: string }[];
}

export const MultiLineChart: React.FC<MultiLineChartProps> = ({ data, lines }) => {
  return (
    <ResponsiveContainer width="100%" height="100%">
      <LineChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
        <XAxis dataKey="date" tick={{fontSize: 10}} axisLine={false} tickLine={false} />
        <YAxis tick={{fontSize: 10}} axisLine={false} tickLine={false} />
        <Tooltip contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} />
        <Legend wrapperStyle={{fontSize: '12px'}} />
        {lines.map((line) => (
          <Line 
            key={line.key}
            type="monotone" 
            dataKey={line.key} 
            stroke={line.color} 
            name={line.name}
            strokeWidth={2}
            dot={{ r: 3 }}
          />
        ))}
      </LineChart>
    </ResponsiveContainer>
  );
};

interface CompetitorChartProps {
  data: CompetitorData[];
}

export const CompetitorChart: React.FC<CompetitorChartProps> = ({ data }) => {
  return (
    <ResponsiveContainer width="100%" height="100%">
      <BarChart data={data} layout="vertical" margin={{ top: 10, right: 30, left: 40, bottom: 0 }}>
        <XAxis type="number" hide />
        <YAxis dataKey="name" type="category" width={90} tick={{fontSize: 10}} />
        <Tooltip cursor={{fill: 'transparent'}} />
        <Legend />
        <Bar dataKey="marketShare" name="市场份额 %" fill="#8884d8" radius={[0, 4, 4, 0]} barSize={15} />
        <Bar dataKey="overlap" name="重叠率 %" fill="#82ca9d" radius={[0, 4, 4, 0]} barSize={15} />
      </BarChart>
    </ResponsiveContainer>
  );
};

interface FunnelChartProps {
  data: { stage: string; value: number; rate: number }[];
}

export const FunnelChart: React.FC<FunnelChartProps> = ({ data }) => {
  return (
    <ResponsiveContainer width="100%" height="100%">
      <BarChart
        layout="vertical"
        data={data}
        margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
      >
        <XAxis type="number" hide />
        <YAxis dataKey="stage" type="category" tick={{fontSize: 12}} width={50} />
        <Tooltip 
             content={({ active, payload }) => {
                if (active && payload && payload.length) {
                return (
                    <div className="bg-white p-2 border border-gray-100 shadow-lg rounded text-xs">
                        <p className="font-bold">{payload[0].payload.stage}</p>
                        <p>量级: {payload[0].value}</p>
                        <p>转化率: {payload[0].payload.rate}%</p>
                    </div>
                );
                }
                return null;
            }}
        />
        <Bar dataKey="value" fill="#6366f1" radius={[0, 4, 4, 0]} barSize={25}>
            {data.map((entry, index) => (
                <Cell key={`cell-${index}`} fillOpacity={1 - (index * 0.1)} />
            ))}
        </Bar>
      </BarChart>
    </ResponsiveContainer>
  );
};

interface DonutChartProps {
    data: { name: string; value: number; color?: string }[];
}

export const DonutChart: React.FC<DonutChartProps> = ({ data }) => {
    const COLORS = ['#FF8042', '#00C49F', '#FFBB28', '#0088FE'];

    return (
        <ResponsiveContainer width="100%" height="100%">
        <PieChart>
            <Pie
                data={data}
                innerRadius={50}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
            >
                {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color || COLORS[index % COLORS.length]} />
                ))}
            </Pie>
            <Tooltip />
            <Legend 
                layout="vertical" 
                verticalAlign="middle" 
                align="right" 
                wrapperStyle={{fontSize: '10px'}}
                formatter={(value, entry: any) => <span style={{ color: '#374151' }}>{value} <span style={{ color: '#9CA3AF' }}>({entry.payload.value})</span></span>}
            />
        </PieChart>
        </ResponsiveContainer>
    );
};

interface HeatmapChartProps {
    data: { industry: string; bidPrice: number; trafficVolume: number; competitionIndex: number }[];
}

export const HeatmapChart: React.FC<HeatmapChartProps> = ({ data }) => {
    const COLORS = ['#ef4444', '#f59e0b', '#10b981', '#3b82f6', '#8b5cf6', '#ec4899'];
    return (
        <ResponsiveContainer width="100%" height="100%">
            <ScatterChart
                margin={{ top: 20, right: 20, bottom: 20, left: 20 }}
            >
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis type="number" dataKey="bidPrice" name="竞价激烈度 (Bid)" tick={{fontSize: 10}} label={{ value: '竞价热度 (Price)', position: 'bottom', fontSize: 10 }} />
                <YAxis type="number" dataKey="trafficVolume" name="流量充裕度 (Traffic)" tick={{fontSize: 10}} label={{ value: '流量规模 (Vol)', angle: -90, position: 'insideLeft', fontSize: 10 }} />
                <ZAxis type="number" dataKey="competitionIndex" range={[60, 400]} name="竞争指数" />
                <Tooltip cursor={{ strokeDasharray: '3 3' }} content={({ active, payload }) => {
                    if (active && payload && payload.length) {
                        const d = payload[0].payload;
                        return (
                            <div className="bg-white p-2 border border-gray-200 shadow-md rounded text-xs">
                                <p className="font-bold">{d.industry}</p>
                                <p>竞价热度: {d.bidPrice}</p>
                                <p>流量规模: {d.trafficVolume}</p>
                                <p>竞争指数: {d.competitionIndex}</p>
                            </div>
                        );
                    }
                    return null;
                }}/>
                <Legend wrapperStyle={{fontSize: '10px', paddingTop: '10px'}} />
                {data.map((entry, index) => (
                    <Scatter 
                        key={index} 
                        name={entry.industry} 
                        data={[entry]} 
                        fill={COLORS[index % COLORS.length]} 
                    />
                ))}
            </ScatterChart>
        </ResponsiveContainer>
    );
};

